import{_ as a,c as o,o as t,ak as r,am as i}from"./chunks/framework.DHLlVITf.js";const f=JSON.parse('{"title":"AireBlocks Configurator Release Notes","description":"","frontmatter":{},"headers":[],"relativePath":"aireblock-releases/aireblocks-configurator-v1-0-0.md","filePath":"aireblock-releases/aireblocks-configurator-v1-0-0.md","lastUpdated":1784558859000}'),s={name:"aireblock-releases/aireblocks-configurator-v1-0-0.md"};function n(l,e,c,h,u,d){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="aireblocks-configurator-release-notes" tabindex="-1"><span class="fsc-product"><img src="'+i+'"> AireBlocks Configurator Release Notes</span> <a class="header-anchor" href="#aireblocks-configurator-release-notes" aria-label="Permalink to “AireBlocks Configurator Release Notes”">​</a></h1><blockquote><p><strong>Version:</strong> 1.0.0<br><strong>Release Date:</strong> 1st July 2026</p></blockquote><h2 id="summary-of-changes" tabindex="-1">Summary of Changes <a class="header-anchor" href="#summary-of-changes" aria-label="Permalink to “Summary of Changes”">​</a></h2><h4 id="✨-new-features" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features" aria-label="Permalink to “✨ New Features”">​</a></h4><ul><li>Global Alert Colour Configuration — SUITECONF-350</li><li>WCAG Accessibility Colour Scoring — SUITECONF-353</li><li>Tenant-Wide Theme Change Warning — SUITECONF-354</li></ul><hr><h1 id="detailed-changes" tabindex="-1">Detailed Changes <a class="header-anchor" href="#detailed-changes" aria-label="Permalink to “Detailed Changes”">​</a></h1><h3 id="✨-new-features-1" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features-1" aria-label="Permalink to “✨ New Features”">​</a></h3><hr><h4 id="global-alert-colour-configuration-suiteconf-350" tabindex="-1">Global Alert Colour Configuration (SUITECONF-350) <a class="header-anchor" href="#global-alert-colour-configuration-suiteconf-350" aria-label="Permalink to “Global Alert Colour Configuration (SUITECONF-350)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Administrators can now configure the colours used for alert messages globally across AireBlocks. The four alert types — Information, Success, Warning, and Danger/Error — each have their own configurable colour, allowing organisations to align alert styling with their custom theme.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You can now ensure that alert messages displayed in AireForms and other AireBlocks products match your organisation&#39;s brand and colour scheme. Set these once in the Configurator and they apply consistently everywhere alerts appear.</p></div><h4 id="wcag-accessibility-colour-scoring-suiteconf-353" tabindex="-1">WCAG Accessibility Colour Scoring (SUITECONF-353) <a class="header-anchor" href="#wcag-accessibility-colour-scoring-suiteconf-353" aria-label="Permalink to “WCAG Accessibility Colour Scoring (SUITECONF-353)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>The theme editor now includes a built-in accessibility scoring engine based on WCAG standards. As you select colours for your theme, the Configurator evaluates your choices and surfaces a score to highlight potential contrast or readability concerns.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You&#39;ll get real-time feedback on whether your colour selections meet accessibility standards, helping you create themes that are usable for all patients and staff — including those with visual impairments. Issues are flagged before the theme is applied, so you can make adjustments with confidence.</p></div><h4 id="tenant-wide-theme-change-warning-suiteconf-354" tabindex="-1">Tenant-Wide Theme Change Warning (SUITECONF-354) <a class="header-anchor" href="#tenant-wide-theme-change-warning-suiteconf-354" aria-label="Permalink to “Tenant-Wide Theme Change Warning (SUITECONF-354)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>When creating or editing a theme, the Configurator now makes it clearly visible that any changes will be applied across the entire tenant, not just the current environment. A warning is displayed at the point of saving or reverting a theme to help prevent unintended broad changes.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You&#39;ll no longer need to guess whether a theme change affects just your environment or your whole organisation. The new warning makes the scope of the change explicit before you confirm, reducing the risk of accidentally applying an unfinished or incorrect theme tenant-wide.</p></div>',18)])])}const m=a(s,[["render",n]]);export{f as __pageData,m as default};
